import{_ as e,c as r,l as a,a as o,t as s,a4 as i,o as l}from"./chunks/framework.CzsDe1xi.js";const P=JSON.parse('{"title":"串行化","description":"","frontmatter":{"title":"串行化"},"headers":[],"relativePath":"doc/数据库/Mysql/基础/事务/串行化.md","filePath":"packages/doc/src/数据库/Mysql/基础/事务/串行化.md","lastUpdated":1711622925000}'),n={name:"doc/数据库/Mysql/基础/事务/串行化.md"},c={id:"frontmatter-title",tabindex:"-1"},d=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),_=i('<h2 id="什么是串行化" tabindex="-1">什么是串行化 <a class="header-anchor" href="#什么是串行化" aria-label="Permalink to &quot;什么是串行化&quot;">​</a></h2><p>串行化是最高的隔离级别，它强制事务串行执行，避免了脏读、不可重复读和幻读等问题。在该级别下，MySQL会对所有读取的数据行都加共享锁或排他锁，直到事务结束。</p><h2 id="为什么需要串行化" tabindex="-1">为什么需要串行化 <a class="header-anchor" href="#为什么需要串行化" aria-label="Permalink to &quot;为什么需要串行化&quot;">​</a></h2><p>在数据库事务中，串行化可以保证多个事务按照指定的顺序执行，从而避免并发冲突。</p><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><p>由于串行化对性能的影响比较大，所以一般情况下不建议使用。只有在确实需要完全隔离、对并发度要求不高的业务场景下才使用。</p>',6);function h(t,p,m,f,u,q){return l(),r("div",null,[a("h1",c,[o(s(t.$frontmatter.title)+" ",1),d]),_])}const k=e(n,[["render",h]]);export{P as __pageData,k as default};
